// ─────────────────────────────────────────────
// SIMULADOR DE BIP (apenas para demonstração)
// ─────────────────────────────────────────────
const playBip = () => {
try {
const ctx = new (window.AudioContext || window.webkitAudioContext)();
// Bip 1
const o1 = ctx.createOscillator();
const g1 = ctx.createGain();
o1.connect(g1); g1.connect(ctx.destination);
o1.frequency.value = 880; o1.type = "sine";
g1.gain.setValueAtTime(0, ctx.currentTime);
g1.gain.linearRampToValueAtTime(0.4, ctx.currentTime + 0.01);
g1.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.18);
o1.start(ctx.currentTime); o1.stop(ctx.currentTime + 0.18);
// Bip 2
const o2 = ctx.createOscillator();
const g2 = ctx.createGain();
o2.connect(g2); g2.connect(ctx.destination);
o2.frequency.value = 1100; o2.type = "sine";
g2.gain.setValueAtTime(0, ctx.currentTime + 0.22);
g2.gain.linearRampToValueAtTime(0.5, ctx.currentTime + 0.23);
g2.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.42);
o2.start(ctx.currentTime + 0.22); o2.stop(ctx.currentTime + 0.42);
// Bip 3
const o3 = ctx.createOscillator();
const g3 = ctx.createGain();
o3.connect(g3); g3.connect(ctx.destination);
o3.frequency.value = 1320; o3.type = "sine";
g3.gain.setValueAtTime(0, ctx.currentTime + 0.46);
g3.gain.linearRampToValueAtTime(0.6, ctx.currentTime + 0.47);
g3.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.75);
o3.start(ctx.currentTime + 0.46); o3.stop(ctx.currentTime + 0.75);
} catch(e) { console.log("Audio não suportado"); }
};

// Validação simples de WhatsApp
const validarWhatsApp = (num) => {
const digits = num.replace(/\D/g, "");
return digits.length >= 10 && digits.length <= 11;
};

